import{c as s,S as t,j as a,m as n}from"./chunks/framework.DvQr6YbT.js";const g=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"developer/architecture.md","filePath":"developer/architecture.md","lastUpdated":1783497907000}'),r={name:"developer/architecture.md"};function i(o,e,d,l,c,h){return t(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to “Architecture”">​</a></h1><p>How Knowlery is put together: one platform-agnostic core, three thin shells, and a workspace format on plain markdown that all of them share.</p><h2 id="one-core-three-shells" tabindex="-1">One core, three shells <a class="header-anchor" href="#one-core-three-shells" aria-label="Permalink to “One core, three shells”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>                    ┌─────────────────────────────┐</span></span>
<span class="line"><span>                    │        src/core/            │</span></span>
<span class="line"><span>                    │  retrieval · staleness ·    │</span></span>
<span class="line"><span>                    │  sync · setup · bundles ·   │</span></span>
<span class="line"><span>                    │  kb-registry · mcp handlers │</span></span>
<span class="line"><span>                    └──────┬───────┬───────┬──────┘</span></span>
<span class="line"><span>                           │       │       │</span></span>
<span class="line"><span>              ┌────────────┴─┐  ┌──┴────┐  └──────────────┐</span></span>
<span class="line"><span>              │ Obsidian     │  │ CLI   │  │ MCP server    │</span></span>
<span class="line"><span>              │ plugin       │  │       │  │ (stdio/HTTP)  │</span></span>
<span class="line"><span>              │ (main.js)    │  │       │  │               │</span></span>
<span class="line"><span>              └──────────────┘  └───────┘  └───────────────┘</span></span></code></pre></div><ul><li><strong>The core</strong> (<code>src/core/</code>) contains all lifecycle logic: setup, sync, retrieval, staleness, bundle export/install/publish/update, the KB registry, and the MCP tool handlers. It never imports Obsidian APIs as values — a test (<code>tests/core/core-purity.test.ts</code>) enumerates the inverted modules and fails on any <code>import ... from &#39;obsidian&#39;</code> that isn&#39;t type-only.</li><li><strong>The Obsidian plugin</strong> (<code>src/main.ts</code>, views, modals) adds the review UI: dashboard, export/install modals, settings, Freshness Review.</li><li><strong>The CLI</strong> (<code>src/cli/</code>) is a thin argv/prompt/output layer. Commands parse flags and delegate; no lifecycle logic lives in the shell.</li><li><strong>The MCP server</strong> (<code>src/core/mcp/</code>) exposes the same operations as tools, prompts, and resources. The stdio shell (<code>knowlery mcp</code>) and the HTTP shell (<code>knowlery mcp serve</code>) supply transports; the handlers don&#39;t know which one is running.</li></ul><p>Two esbuild bundles come out of one repository: <code>main.js</code> (plugin) and <code>knowlery-cli.mjs</code> (CLI + MCP). The MCP SDK is bundled into the CLI artifact only — the plugin bundle contains no MCP code.</p><h2 id="the-file-system-inversion" tabindex="-1">The file-system inversion <a class="header-anchor" href="#the-file-system-inversion" aria-label="Permalink to “The file-system inversion”">​</a></h2><p>The core reaches disk through a <code>VaultFs</code> interface (<code>src/core/vault-fs.ts</code>) with two implementations:</p><table tabindex="0"><thead><tr><th>Implementation</th><th>Backing</th><th>Used by</th></tr></thead><tbody><tr><td><code>obsidianVaultFs</code></td><td>Obsidian <code>App</code> vault API</td><td>plugin</td></tr><tr><td><code>nodeVaultFs</code></td><td><code>node:fs</code></td><td>CLI, MCP, tests</td></tr></tbody></table><p><code>loggingVaultFs</code> wraps either to record which paths a sync actually wrote — that&#39;s how <code>sync</code> reports its file list and proves idempotence in tests. Wikilink resolution has the same split: the plugin uses Obsidian&#39;s <code>metadataCache</code>; headless code scans files, and ambiguous basenames resolve to nothing rather than guessing.</p><h2 id="the-workspace-format" tabindex="-1">The workspace format <a class="header-anchor" href="#the-workspace-format" aria-label="Permalink to “The workspace format”">​</a></h2><p>A Knowlery workspace is a plain folder:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>KNOWLEDGE.md          # the agent-facing operating guide</span></span>
<span class="line"><span>SCHEMA.md             # living taxonomy conventions</span></span>
<span class="line"><span>INDEX.base            # Obsidian Bases index</span></span>
<span class="line"><span>entities/ concepts/ comparisons/ queries/    # compiled layer (agent-tier)</span></span>
<span class="line"><span>inbox/                # MCP capture landing zone (user-tier, created on demand)</span></span>
<span class="line"><span>Library/&lt;bundle-id&gt;/  # installed bundles (read-only reference)</span></span>
<span class="line"><span>.knowlery/            # manifest, bundles.json, exports, activity, reports</span></span>
<span class="line"><span>.agents/skills/ .claude/skills/              # installed skill packages</span></span></code></pre></div><p>Pages are markdown with frontmatter. The scanner (<code>src/core/query/scan.ts</code>) classifies every page into a tier: <code>agent</code> (the four compiled dirs), <code>user</code> (everything else), or bundle material under <code>Library/</code>. That tier drives retrieval weighting, staleness, and the MCP resource allowlist.</p><p>The manifest (<code>.knowlery/manifest.json</code>) records platform, KB name, and <code>lastSyncedBy</code> — the version stamp behind the downgrade guard.</p><h2 id="the-retrieval-engine" tabindex="-1">The retrieval engine <a class="header-anchor" href="#the-retrieval-engine" aria-label="Permalink to “The retrieval engine”">​</a></h2><p><code>src/core/query/</code> is pure TypeScript with no I/O beyond the initial scan:</p><ol><li><strong>Tokenize</strong> the question: latin words with light stemming variants, CJK substrings and phrases.</li><li><strong>Score</strong> every page with field weights — title and aliases dominate, then tags, description, body. A compiled page is credited when a raw note it cites (via <code>sources:</code>) matches the question, which is how cross-language questions reach compiled answers.</li><li><strong>Gate</strong> the result: the top candidate must clear a confidence bar — structured-field hits with sufficient specificity-weighted term coverage, strong prose coverage, or pure source-graph reach. Otherwise the verdict is <code>no-confident-match</code> and the engine abstains rather than ranking noise.</li></ol><p>There is deliberately <strong>no cache and no index</strong>: every query is a live scan. Vault-scale corpora scan in milliseconds, and statelessness removes the entire invalidation problem — the same property that later made the MCP server restart-safe for free.</p><p>The same snapshot feeds <strong>staleness</strong> (<code>staleness.ts</code>): a compiled page is stale when a cited source&#39;s mtime is newer than the page&#39;s; user notes cited by nothing are &quot;uncooked&quot;; citations pointing at missing files are dangling. Everything is computed fresh from mtimes — no bookkeeping state.</p><p>Retrieval quality is <strong>measured, not asserted</strong>: <code>evals/</code> contains fixture vaults and a golden question set; CI runs recall@10 / MRR against a frozen baseline and fails any change that drops below it.</p><h2 id="knowledge-bundles-okf" tabindex="-1">Knowledge bundles (OKF) <a class="header-anchor" href="#knowledge-bundles-okf" aria-label="Permalink to “Knowledge bundles (OKF)”">​</a></h2><p>A bundle is a zip of approved compiled pages plus <code>knowlery-bundle.json</code> (manifest: id, version, creator, content hash), <code>index.md</code> and <code>agent-index.json</code> for navigation, approved raw sources under <code>_sources/</code>, and a schema scoped to the tags the bundle actually uses.</p><p>The pipeline (<code>src/core/okf/</code>) is gate-shaped:</p><ul><li><strong>Export</strong>: seed topic → graph closure → per-item review (approve/flag with content hashes, so edits re-invalidate approval) → risk scan (emails, sensitive URLs, credential patterns, person pages) → compile → zip.</li><li><strong>Publish</strong>: <code>gh</code> CLI creates a GitHub Release with a SHA-256 in the notes; public repos require a second acknowledgment of every risk item.</li><li><strong>Install</strong>: local path or URL; private release assets download through the user&#39;s <code>gh</code> login; <code>--verify &lt;sha256&gt;</code> checks integrity; conformance validates structure before anything is written.</li><li><strong>Update</strong>: <code>check-updates</code> reads release feeds read-only; <code>update</code> requires a version increase, stages the new content in a temp directory, detects local modifications by hash, and performs an atomic swap with a backup.</li></ul><h2 id="the-kb-registry" tabindex="-1">The KB registry <a class="header-anchor" href="#the-kb-registry" aria-label="Permalink to “The KB registry”">​</a></h2><p><code>~/.config/knowlery/registry.json</code> maps names to canonical paths — nothing more. All shells share it: the CLI&#39;s <code>--kb</code>, the plugin&#39;s self-registration (ownership-tracked so it never removes a user&#39;s entry), and the MCP server&#39;s addressing layer. Names are validated at write <em>and</em> at read (a hand-edited invalid entry is a loud error, never silent data loss). Federated query iterates the registry, runs the engine per KB, and merges by score with per-KB attribution.</p><h2 id="the-mcp-server" tabindex="-1">The MCP server <a class="header-anchor" href="#the-mcp-server" aria-label="Permalink to “The MCP server”">​</a></h2><p><code>src/core/mcp/server.ts</code> registers everything on an SDK <code>McpServer</code>:</p><ul><li><strong>Eight tools</strong> — five reads (<code>list_kbs</code>, <code>query</code>, <code>stale</code>, <code>health</code>, <code>list_bundles</code>) and three writes (<code>init_kb</code>, <code>capture</code>, <code>sync</code>) — each with zod input schemas (strict: unknown fields rejected) and <code>structuredContent</code> mirroring the CLI&#39;s <code>--json</code> shapes.</li><li><strong>Prompts</strong>: nine curated skills served verbatim.</li><li><strong>Resources</strong>: <code>knowlery://{kb}/{+path}</code> with a read allowlist covering only the curated surface (<code>KNOWLEDGE.md</code>, compiled dirs, <code>Library/</code>) — canonicalize-then-prefix-check, so traversal and symlink escapes are refused.</li></ul><p>Access is <strong>structural</strong>: the <code>access</code> option decides which write tools get registered at all. stdio registers everything (the caller owns the machine); the HTTP shell fails closed and registers only what <code>--allow-*</code> flags opted into.</p><p>The HTTP shell (<code>http-server.ts</code>) keeps one long-lived <code>node:http</code> server but builds a <strong>fresh McpServer + stateless transport pair per request</strong>, closing both with the response — the SDK&#39;s stateless-mode contract. Auth is a bearer token compared with <code>timingSafeEqual</code> over hashes; the token is never stored or logged.</p><h2 id="testing-strategy" tabindex="-1">Testing strategy <a class="header-anchor" href="#testing-strategy" aria-label="Permalink to “Testing strategy”">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Approach</th></tr></thead><tbody><tr><td>Core logic</td><td>Unit tests on pure functions (engine, staleness, zip, registry)</td></tr><tr><td>Command handlers</td><td>In-memory <code>VaultFs</code> + temp dirs; injected failures for cleanup paths</td></tr><tr><td>MCP</td><td>Protocol round trips over the SDK&#39;s in-memory transport — no subprocesses</td></tr><tr><td>Built artifact</td><td>A smoke test builds <code>knowlery-cli.mjs</code> with the release entry point and drives it end to end: init → sync → query → bundles → remote install → registry → MCP stdio → HTTP serve</td></tr><tr><td>Retrieval quality</td><td>The eval harness with a CI-enforced baseline</td></tr><tr><td>Purity</td><td>The inverted-module list, enforced by test</td></tr></tbody></table><h2 id="versioning-and-release" tabindex="-1">Versioning and release <a class="header-anchor" href="#versioning-and-release" aria-label="Permalink to “Versioning and release”">​</a></h2><p>Plugin and CLI version in lockstep (one <code>package.json</code>). Releases run on version tags; npm publishing uses OIDC trusted publishing (no tokens in CI) with provenance, and is idempotent — a re-run of a tag that already published skips green. The workspace format, CLI surface, and MCP tool contracts freeze at 1.0 under semver.</p>`,36)])])}const u=s(r,[["render",i]]);export{g as __pageData,u as default};
